UPDATE augments SET description = 'Gain {{cai|Hemorrhage|Darius}}.<br><br>{{sbc|Passive:}} Damaging basic attacks and abilities apply a stack of ''''Hemorrhage'''' to enemies for 5 seconds, refreshing on subsequent applications and stacking up to 5 times.<br><br>{{sbc|Hemorrhage:}} For each stack, the target is dealt {{ft|{{as|{{pp|15 to 45}}|physical damage}} {{as|(+ 40% AD)}} {{as|''''''total'''''' physical damage}}|{{as|{{pp|15/4 to 45/4}}|physical damage}} {{as|(+ {{ap|40/4}}% AD)}} {{as|physical damage}} every {{fd|1.25}} seconds}} over the duration, up to a maximum of{{ft|{{as|{{pp|15*5 to 45*5}}|physical damage}} {{as|(+ {{ap|40*5}}% AD)}} {{as|''''''total'''''' physical damage}} over the duration.|{{as|{{pp|(15/4)*5 to (45/4)*5}}|physical damage}} {{as|(+ {{ap|(40/4)*5}}% AD)}} {{as|physical damage}} with each tick.}}<br><br>{{sbc|Noxian Might:}} When you apply 5 stacks of ''''Hemorrhage'''' to an enemy champion, become empowered with ''''Noxian Might'''' for 5 seconds, granting you {{pp|30 to 75 for 10;90 to 120 for 3;150 to 270 for 5|formula=30 + 5 per level until level 10, then + 15 per level until level 13, then + 30 per level|color=AD}} {{sti|{{as|''''''bonus'''''' attack damage}}}}.<br><br>''''This augment is only available for {{ci|Draven}}.''''', tier = 'Gold', notes = NULL WHERE name = 'Blood Brother';
