UPDATE augments SET description = 'Gain {{cai|Center of the Universe|Aurelion Sol}}.<br><br>{{sbc|Center of the Universe:}} You are now permanently orbited by 6 ''''Stars'''' that exist {{tt|at your attack range|At the beginning of the current phase}}, and rotate clockwise one after another at the same constant speed.<br><br>Each ''''Star'''' deals {{as|{{pp|5 to 160}}|magic damage}} {{as|(+ 25% ''''''bonus'''''' AD)}} {{as|(+ 12% AP)}} {{as|magic damage}} to enemies that come into contact with it and has a width of {{tip|er|icononly=true}} 50 units.', tier = 'Prismatic', notes = NULL WHERE name = 'Center of the Universe';
UPDATE augments SET description = 'Dealing damage to an enemy champion also damages the nearest other champion within 800 units of them for {{sti|{{as|true damage}}}} equal to a portion of damage instance {{tt|post-mitigation|Damage calculated after modifiers}}.', tier = 'Prismatic', notes = NULL WHERE name = 'Chain Lightning';
UPDATE augments SET description = 'Become {{tip|attach|attached}} to your ally for the rest of the game, granting them {{sti|{{as|100% of your ''''''bonus'''''' movement speed}}}} as well as gaining {{sti|{{as|ability haste}}}} and {{sti|{{as|''''''bonus'''''' attack speed}}}}.<br><br>{{tip|Dash|Dashing}} or {{tip|blink|blinking}} detaches you for {{fd|1.5}} seconds before attaching you back to your ally. While your ally is downed, the link is temporarily broken.', tier = 'Prismatic', notes = '* When {{cai|The Show Stopper|Sett}} is used on you, you will not reattach to your ally until you {{tip|dash}} or {{tip|blink}} again.
        * When {{cai|Realm of Death|Mordekaiser}} is used on you, your hitbox stays attached to your ally''s location while you appear to stand at the position where you entered the ''''Death Realm''''.{{bug}}
        ** When casting an ability, your champion will ''''''visually'''''' teleport to your real location, before ''''''visually'''''' teleporting back once the cast is over.
        * When {{cai|Realm of Death|Mordekaiser}} is used on your ally, you will follow them into the ''''Death Realm''''.
        ** You will, however, only follow them back out of the ''''Death Realm'''' if you are attached or once you reattach to them.{{bug}}
        *** In the case that you find a way to never reattach, you can stay in the ''''Death Realm'''' until the round is over.' WHERE name = 'Chauffeur';
UPDATE augments SET description = '{{tip|Heal|Healing}} and {{stil|health regeneration}} you do causes you to deal a ratio of that value in {{as|magic damage}} to the nearest enemy champion within 1000 units.', tier = 'Prismatic', notes = NULL WHERE name = 'Circle of Death';
UPDATE augments SET description = 'Form a {{tip|tether}} between you and your ally that continuously {{as|Burns}} enemies it touches, dealing {{as|magic damage}} every {{fd|0.25}} seconds. The tether has a width of {{tip|er|icononly=true}} 100 units. ''''Attributes the damage to the player who has equipped Clothesline.''''', tier = 'Silver', notes = NULL WHERE name = 'Clothesline';
UPDATE augments SET description = 'Gain the {{ri|Electrocute}} and {{ri|Phase Rush}} keystone runes.<br><br>''''See [[Arena#Runes]] for Arena-specific overrides on these runes.''''', tier = 'Gold', notes = NULL WHERE name = 'Combo Master';
UPDATE augments SET description = 'At the start of the combat phase in each round, mark a champion on the enemy team. The mark causes them to take increased damage from your team and dispense an ''''''additional'''''' kill bounty of {{g|150}} when slain. This bounty is granted to both you and your ally when the marked target is slain.<br><br>Each enemy champion can only have one mark per round.', tier = 'Silver', notes = NULL WHERE name = 'Contract Killer';
UPDATE augments SET description = '{{tip|immobilize|Immobilizing}} or {{tip|ground|grounding}} an enemy champion grants a shield based on {{as|your ''''''maximum'''''' health}} for 3 seconds ({{sti|5 seconds cooldown}} per {{tip|cast instance}}). Shields can stack between multiple triggers of this effect, though not refreshing the duration of previous shields.', tier = 'Prismatic', notes = NULL WHERE name = 'Courage of the Colossus';
UPDATE augments SET description = 'Your {{tip|heals}} and {{tip|shields}} now have a chance equal to your {{sti|{{as|critical strike chance}}}} to increase. The effectiveness benefits from your {{sti|critical strike damage|{{as|crit damage}}}}. Additionally, gain {{sti|{{as|25% critical strike chance}}}}.', tier = 'Gold', notes = NULL WHERE name = 'Critical Healing';
UPDATE augments SET description = 'Abilities with {{tip|dash|dashes}} or {{tip|blink|blinks}} gain {{sti|{{as|ability haste}}}}.<br><br>On {{ci|Kalista}}, {{ais|Martial Poise|Kalista}} dash gains {{sti|{{as|''''''bonus'''''' movement speed}}}} toward its speed scaling instead.', tier = 'Prismatic', notes = NULL WHERE name = 'Dashing';
