UPDATE augments SET description = 'Gain and activate {{cai|Poison Trail|Singed}}.<br><br>{{sbc|Poison Trail:}} Gain {{tip|ghosting}} and continually create a toxic cloud behind you that lingers for {{fd|3.25}} seconds. The cloud inflicts {{tip|poison}} to enemies within every {{fd|0.5}} seconds, which deals {{as|{{pp|15/4 to 125/4}}|magic damage}} {{as|(+ {{ap|20/4}}% ''''''bonus'''''' AD)}} {{as|(+ {{ap|10/4}}% AP)}} {{as|magic damage}} every {{fd|0.25}} seconds over 2 seconds.', tier = 'Silver', notes = NULL WHERE name = 'Don''t Chase';
UPDATE augments SET description = 'Become {{tip|melee}}, modifying your [[attack range]] to 200 units. Additionally, gain {{sti|{{as|''''''bonus'''''' attack damage}}}}, {{sti|{{as|''''''bonus'''''' attack speed}}}}, {{sti|{{as|''''''bonus'''''' health}}}}, {{sti|{{as|15% ''''''bonus'''''' movement speed}}}} and {{sti|{{as|25% life steal}}}}. These bonuses are increased by {{pp|key=%|type=champion''s default attack range|0 to 30 for 11|500 to 650|formula=3% for every 15 attack range starting from 500 attack range and with the maximum at 650 range}}.<br><br>''''This augment is only available for {{tip|ranged}} champions.''''', tier = 'Prismatic', notes = NULL WHERE name = 'Draw Your Sword';
