UPDATE augments SET description = 'Your next basic attack in each cardinal direction within {{sti|attack range|750 range}} additionally {{tip|on-attack}} fires 5 bolts at the target that each deals {{as|{{pp|10 to 52.5}}|physical damage}} {{as|(+ 15% ''''''bonus'''''' AD)}} {{as|physical damage}}. Each direction has {{sti|unique cooldown}}. Bolts'' damage is increased by {{pp|type=distance travelled|0 to 50 for 11|0 to 750|key=%}}. Each bolt can {{tip|critically strike}} and applies {{tip|on-hit}} effects at 20% effectiveness.', tier = 'Prismatic', notes = NULL WHERE name = 'Fan the Hammer';
UPDATE augments SET description = 'Replaces {{si|Flee}} with ''''{{si|Feel the Burn}}''''.<br><br>[[File:Feel the Burn augment spell.png|20px|link=]] {{sbc|Feel the Burn:}} {{#invoke:SpellData|geteffect|Feel the Burn}}<br><br>This counts as a {{as|Burn}} source.', tier = 'Prismatic', notes = NULL WHERE name = 'Feel the Burn';
UPDATE augments SET description = 'Damaging enemies with your ultimate ability {{tip|polymorph|polymorphs}} them into harmless critters for 2 seconds, during which their {{sti|{{as|''''''base'''''' movement speed}}}} is reduced by {{as|60|ms}}, and {{tip|disarm|disarms}} them for the same duration ({{sti|15 seconds cooldown}} per target).', tier = 'Prismatic', notes = NULL WHERE name = 'Fey Magic';
UPDATE augments SET description = 'Upon selecting this augment, all of your current items are sold to the shop at a higher {{g|gold}} value ''''({{sbc|Starter Items & Boots:}} {{g|500}}, {{sbc|Legendary Item:}} {{g|2500}}, {{sbc|Prismatic Item:}} {{g|4000}}).''''<br><br>Quest items ({{ii|Needlessly Large Rod}}, {{ii|The Golden Spatula}}, {{ii|Wooglet''s Witchcap}}, as well as {{ii|Heartsteel}} if you have the [[File:Quest Steel Your Heart ar augment.png|20px|link=]] ''''Quest: Steel Your Heart'''' augment) and consumables will not be sold from this effect.<br><br>When this augment is removed or replaced, gain {{g|gold}} equal to 30% of {{g|gold}} gained from this augment.', tier = 'Silver', notes = NULL WHERE name = 'Fire Sale';
UPDATE augments SET description = 'Basic attacks {{tip|on-hit}} apply a {{as|Burn}} for 5 seconds that deals {{as|''''''bonus'''''' magic damage}} based on {{as|the target''s ''''''maximum'''''' health}}. This {{as|Burn}} stacks infinitely and refreshes with each application.<br><br>This counts as a {{as|Burn}} source.', tier = 'Gold', notes = NULL WHERE name = 'Firebrand';
UPDATE augments SET description = 'Grants {{stil|{{as|heal and shield power}}}}.', tier = 'Silver', notes = NULL WHERE name = 'First-Aid Kit';
