UPDATE augments SET description = 'Your {{si|Flash}} now has multiple charges with a {{sti|2-second cooldown}} between casts, gaining maximum charges at the start of each phase in a round. Additionally, the cooldown of your {{si|Flash}} resets every round.', tier = 'Gold', notes = NULL WHERE name = 'Flashy';
UPDATE augments SET description = 'Gain the {{ri|Dark Harvest}} and {{ri|First Strike}} keystone runes. Additionally, for each augment equipped before selecting this one, gain 8 {{as|Souls}} of {{ri|Dark Harvest}} for free.<br><br>''''See [[Arena#Runes]] for Arena-specific overrides on these keystones.''''', tier = 'Gold', notes = NULL WHERE name = 'From Beginning to End';
UPDATE augments SET description = '{{as|Automatically}} cast {{cai|Ring of Frost|Lissandra}}, creating a cold pulse around you in {{tip|cr|icononly=true}} 450 radius that {{tip|root|roots}} nearby enemies for {{fd|1.25}} seconds ({{sti|{{fd|6.5}} seconds cooldown}}).', tier = 'Silver', notes = NULL WHERE name = 'Frost Wraith';
UPDATE augments SET description = 'Replaces {{si|Flee}} with ''''{{si|Frozen Foundations}}''''.<br><br>[[File:Crystallized Will augment spell.png|20px|link=]] {{sbc|Frozen Foundations:}} {{#invoke:SpellData|geteffect|Frozen Foundations}}', tier = 'Silver', notes = NULL WHERE name = 'Frozen Foundations';
UPDATE augments SET description = 'Increase the effects of [[File:Power FlowerSquare.png|20px|link=Arena#Power Flowers|An icon representing the Power Flower plant]] ''''[[Arena#Power Flowers|Power Flowers]]''''. When you hit a ''''Power Flower'''', your teammate gains its effects as well regardless of range and you both gain {{sti|{{as|40% ''''''bonus'''''' movement speed}}}} for 2 seconds.', tier = 'Silver', notes = '* When you share a ''''Power Flower'''' with your teammate, they will neither benefit from your nor their increased ''''Power Flower'''' effect.
			* The increased ''''Power Flower'''' effect {{tip|stacks additively}} with {{tt|{{iis|Guardian''s Dirk}}|Starter items gone}} {{nie|Agricultural Reaper}} for a total of {{pp|type=augment level|40%;60%}} increased ''''Power Flower'''' effectiveness.' WHERE name = 'Fruits of Your Labor';
UPDATE augments SET description = 'Gain {{g|1000}}. Additionally, in your Shop, the cost of {{ii|Prismatic Item|Prismatic Item Anvils}}, all {{ii|Legendary Fighter Item|icononly=true}}{{ii|Legendary Marksman Item|icononly=true}}{{ii|Legendary Assassin Item|icononly=true}}{{ii|Legendary Mage Item|icononly=true}}{{ii|Legendary Tank Item|icononly=true}}{{ii|Legendary Support Item|icononly=true}} Legendary Item Anvils and {{ii|Stat Bonus|Stat Bonus Anvils}} is reduced. The resale value of all ''''Prismatic items'''' and ''''Legendary items'''' is also reduced.', tier = 'Prismatic', notes = '* You will keep Gamba Anvils discounts even after losing the Augment.{{bug}}' WHERE name = 'Gamba Anvil';
UPDATE augments SET description = 'Become tiny, reducing your {{sti|size}} and gaining {{sti|{{as|''''''bonus'''''' movement speed}}}}. Additionally, deal ''''''bonus'''''' damage against enemy champions with greater [[size]] than you.', tier = 'Prismatic', notes = NULL WHERE name = 'Giant Slayer';
