UPDATE augments SET description = 'Basic attacks deal {{as|''''''bonus'''''' physical damage}} equal to {{sti|{{as|a percentage of your ''''''maximum'''''' health}}}}.', tier = 'Silver', notes = '* ''''''Heavy Hitter'''''' is not and does not interact with {{tip|on-hit}} effects.
		* ''''''Heavy Hitter'''''' deals {{tip|proc damage}}.' WHERE name = 'Heavy Hitter';
UPDATE augments SET description = 'Gain an improved version of {{cai|Guerrilla Warfare|Teemo}}.<br><br>{{sbc|Guerrilla Warfare:}} Gain {{tip|invisibility}} after {{fd|0.75}} seconds without moving, being {{tip|immobilize|immobilized}}, taking damage, performing actions that {{tip|break stealth}}, {{tip|channel|channeling}}, or being in {{tip|stasis (buff)|stasis}}. Upon exiting stealth, gain {{sti|{{as|{{pp|key=%|20 to 80 for 4|1;5;10;15}} ''''''bonus'''''' attack speed}}}} for 5 seconds and {{sti|{{as|100% ''''''bonus'''''' movement speed}}}} decaying over the same duration. Your next attack after exiting stealth deals {{pp|60 to 200|color=magic damage}} {{as|(+ 60% ''''''bonus'''''' AD)}} {{as|(+ 40% AP)}} {{as|''''''bonus'''''' magic damage}}.<br><br>''''Invisibility is granted immediately at the start of the combat phase.''''', tier = 'Silver', notes = NULL WHERE name = 'Hold Very Still';
UPDATE augments SET description = 'Your {{tip|heals}} and {{tip|shields}} cause you to fire a missile to the nearest enemy champion within {{tip|cr|icononly=true}} 650 units over {{fd|0.32}} seconds, applying a {{as|Burn}} upon arrival that deals {{as|magic damage}} based on {{sti|{{as|the target''s ''''''maximum'''''' health}}}} over time.<br><br>The {{as|Burn''s}} per-tick damage increases based on the relative value of the triggering {{tip|heal}} or {{tip|shield}} against the {{sti|{{as|''''''maximum'''''' health}}}} of the ally recipient.<br><br>This counts as a {{as|Burn}} source.', tier = 'Gold', notes = NULL WHERE name = 'Holy Fire';
UPDATE augments SET description = 'Gain {{sti|{{as|''''''bonus'''''' movement speed}}}}. This bonus is lost for 3 seconds after dealing damage to or taking damage from champions.', tier = 'Silver', notes = NULL WHERE name = 'Homeguard';
