UPDATE augments SET description = 'Your ability hits apply a {{as|Burn}} for 5 seconds that deals persistent {{as|magic damage}} ({{sti|1 second cooldown}} per {{tip|cast instance}}). This {{as|Burn}} stacks infinitely and refreshes with each application. Damage over time abilities can apply the effect only once every 2 seconds.<br><br>Additionally, all of your {{as|Burn}} effects reduce the {{sti|cooldowns}} of all your basic abilities for each tick of damage they deal to a target.<br><br>This counts as a {{as|Burn}} source.', tier = 'Prismatic', notes = NULL WHERE name = 'Infernal Conduit';
UPDATE augments SET description = 'Grants the {{bi|Infernal Dragon Soul}}, or a different {{bi|Dragon Soul}} if one is already obtained.', tier = 'Silver', notes = NULL WHERE name = 'Infernal Soul';
UPDATE augments SET description = 'Grants {{sti|{{as|critical strike chance}}}}.', tier = 'Gold', notes = NULL WHERE name = 'It''s Critical';
UPDATE augments SET description = 'Upon casting your ultimate ability, you apply {{cai|Death Mark|Zed}} to all enemy champions ({{sti|8 seconds cooldown}}). The mark stores a percentage of all {{tt|post-mitigation|Damage calculated before modifiers}} damage dealt to the affected target, detonating after 5 seconds to deal {{sti|{{as|true damage}}}} equal to the damage stored against them.<br><br>If this augment''s cooldown elapses during the channel of {{cai|Crowstorm|Fiddlesticks}}, {{cai|Hero''s Entrance|Galio}} or {{cai|Grand Starfall|Pantheon}}, this effect activates right before their first respective damaging effect activates.', tier = 'Gold', notes = '* The damage from ''''''It''s Killing Time'''''' benefits from ultimate damage modifiers.' WHERE name = 'It''s Killing Time';
UPDATE augments SET description = 'Your abilities can now {{tip|critical strike|critically strike}} to deal higher damage. Additionally, gain {{sti|{{as|critical strike chance}}}} based on your {{sti|{{as|ability power}}}}.<br><br>If both ''''Jeweled Gauntlet'''' and [[File:Vulnerability ar augment.png|20px|link=|An icon for the Arena augment Vulnerability]] ''''Vulnerability'''' are equipped, only rolls the {{sti|{{as|critical strike chance}}}} of the augment that has the higher {{sti|{{as|critical damage}}}} (or either if equal).', tier = 'Prismatic', notes = NULL WHERE name = 'Jeweled Gauntlet';
UPDATE augments SET description = 'Each round, you and your ally gain several ''''Juices'''' ({{ii|Cappa Juice|icononly=true}} {{ii|Juice of Haste|icononly=true}} {{ii|Juice of Power|icononly=true}} {{ii|Juice of Vitality|icononly=true}}) for free that is automatically consumed at the start of the combat phase.', tier = 'Silver', notes = NULL WHERE name = 'Juice Box';
UPDATE augments SET description = 'Gain the {{ri|Arcane Comet}} and {{ri|Summon Aery}} keystone runes.<br><br>''''See [[Arena#Runes]] for Arena-specific overrides on {{ri|Summon Aery}}.''''', tier = 'Gold', notes = NULL WHERE name = 'Keystone Conjurer';
UPDATE augments SET description = 'Continuously fire a laser in a line 700 units from your facing direction, dealing {{as|{{pp|5 to 60}}|magic damage}} {{as|(+ {{ap|56/4}}% AD)}} {{as|(+ {{ap|36/4}}% AP)}} {{as|magic damage}} every {{fd|0.25}} seconds to enemies in its width of 80 units.', tier = 'Prismatic', notes = NULL WHERE name = 'Laser Eyes';
UPDATE augments SET description = 'Basic attacks {{tip|on-hit}} generate a stack, up to 4. The fourth stack consumes them all to quickly launch 4 fireworks at the target that deal {{as|{{pp|11 to 80}}|magic damage}} {{tip|on-hit}}.', tier = 'Silver', notes = NULL WHERE name = 'Light ''em Up!';
UPDATE augments SET description = '{{as|Automatically}} cast {{cai|Prismatic Barrier|Lux}}, throwing a warding light towards your ally which grants a {{tip|shield}} for {{pp|25+3*x}} {{as|(+ {{fd|7.5}}% ''''''bonus'''''' AD)}} {{as|(+ 20% AP)}} to you and your ally for {{fd|2.5}} seconds upon coming into contact with it. After reaching maximum range, the light then homes back to you to grant the same shield again when it passes through you and your ally, stacking with the previous shield and refreshing its duration ({{sti|8 seconds cooldown}}).', tier = 'Gold', notes = NULL WHERE name = 'Light Warden';
