UPDATE augments SET description = 'Dealing damage to an enemy with an ability within {{tip|cr|icononly=true}} 1000 units fires several missiles at them that each deal {{as|true damage}} equal to {{as|{{fd|0.3{{recurring|3}}}}% of the target''s ''''''maximum'''''' health}}, increased to up to {{as|1%|health}} based on distance travelled. This effect can only trigger once every 6 seconds from the same cast.', tier = 'Gold', notes = NULL WHERE name = 'Magic Missile';
UPDATE augments SET description = 'Basic attacks deal {{as|''''''bonus'''''' physical damage}} based on your {{sti|{{as|ability power}}}}.', tier = 'Gold', notes = '* ''''''Marksmage'''''' is not and does not interact with {{tip|on-hit}} effects.
		* ''''''Marksmage'''''' deals {{tip|proc damage}}.' WHERE name = 'Marksmage';
UPDATE augments SET description = 'Basic attacks {{tip|on-hit}} grant {{sti|{{as|{{pp|6 to 18}} ability power}}}} and ability casts grant {{sti|{{as|{{pp|3 to 9}} ''''''bonus'''''' attack damage}}}}. This effect stacks infinitely and lasts until the end of the current round phase.', tier = 'Prismatic', notes = NULL WHERE name = 'Master of Duality';
UPDATE augments SET description = 'Grants {{sti|{{as|''''''bonus'''''' health}}}} equal to a percentage of {{sti|{{as|your ''''''maximum'''''' mana}}}}.', tier = 'Silver', notes = NULL WHERE name = 'Mind to Matter';
UPDATE augments SET description = 'Your {{tip|pet|pets}} deal increased damage as well as gain {{sti|{{as|''''''bonus'''''' health}}}} and {{sti|size}}.', tier = 'Gold', notes = NULL WHERE name = 'Minionmancer';
UPDATE augments SET description = 'Gain an improved version of {{cai|Mirror Image|LeBlanc}}.<br><br>{{sbc|Mirror Image:}} Upon being damaged to {{sti|{{as|30% ''''''maximum'''''' health}}}}, create 4 {{tip|clone|clones}} of yourself, after which you and your clones instantly become {{tip|invisible}} for {{fd|1.25}} seconds ({{sti|30 seconds cooldown}}). Your clones can mimic your [[basic attack]] animation, though cannot deal damage and last for 8 seconds. One clone may move in front of you, the others will move toward random directions. ''''Clones have a {{g|25}} bounty.''''', tier = 'Silver', notes = NULL WHERE name = 'Mirror Image';
UPDATE augments SET description = 'Grants the {{bi|Mountain Dragon Soul}}, or a different {{bi|Dragon Soul}} if one is already obtained.', tier = 'Silver', notes = NULL WHERE name = 'Mountain Soul';
