UPDATE augments SET description = 'Upon taking fatal damage, you enter a [[Arena#Revival|downed state]] as normal but modify the arm time for the revive and automatically revive yourself without the help of your ally over 8 seconds. Additionally, you can enter the downed state for revival an additional time after the first revive, for a total of 2 revives per round. Each time you revive however, you respawn with reduced {{sti|{{as|''''''maximum'''''' health}}}} and {{sti|size}}. The first revive reduces your {{sti|{{as|''''''maximum'''''' health}}}} by {{as|20%|hp}} and {{sti|size}} by 20% and the second does so by {{as|36%|hp}} and 40% ({{as|80% ''''''total maximum'''''' health}} and 80% size for first revive, then {{as|64% ''''''total maximum'''''' health}} and 60% size for the second), and so on.<br><br>This effect only activates while your ally is alive and is cancelled immediately if they die while you are in the downed state. You and your ally can enter the downed state even after one of you has already been revived from one, though not a second time for your ally. If your ally stands in your revival zone, the revive occurs faster. Upon reviving, you {{tip|airborne|knock back}} all nearby enemies.', tier = 'Prismatic', notes = NULL WHERE name = 'Nesting Doll';
UPDATE augments SET description = 'Replaces {{si|Flee}} with ''''{{si|Now You See Me}}''''.<br><br>[[File:Now You See Me augment spell.png|20px|link=]] {{sbc|Now You See Me:}}<br><br>{{#invoke:SpellData|geteffect|Now You See Me}}<br><br>{{#invoke:SpellData|geteffect2|Now You See Me}}', tier = 'Silver', notes = '* You can decide which portal to teleport to by moving your mouse cursor to that portal.' WHERE name = 'Now You See Me';
UPDATE augments SET description = 'Replaces {{si|Flee}} with ''''{{cai|Fate''s Call|Kalista}}''''.<br><br>{{sbc|Fate''s Call:}} Retrieve your ally and hold them for 4 seconds, {{tip|dash|pulling}} them to yourself over 1 second and {{tip|cleanse|cleansing}} them from all {{tip|crowd control}}, as well as rendering them {{tip|invulnerable}} and {{tip|untargetable}} for the duration ({{sti|60 seconds cooldown}}).<br><br>While being held, your ally is {{tip|vanish|vanished}} and can {{tip|dash}} with {{tip|displacement immunity}} to end ''''Fate''s Call''s'''' effects and reappear at the target location; after the duration, they will automatically do so at maximum range from your facing direction. The ally''s dash stops upon colliding with an enemy {{tip|champion}}, {{tip|airborne|knocking}} up all nearby enemies briefly and landing to their {{sti|attack range|{{as|''''''base'''''' attack range}}}} from the target collided with.', tier = 'Gold', notes = NULL WHERE name = 'Oathsworn';
UPDATE augments SET description = 'Grants the {{bi|Ocean Dragon Soul}}, which has a modified base {{tip|heal}} value of 100, or a different {{bi|Dragon Soul}} if one is already obtained.', tier = 'Silver', notes = NULL WHERE name = 'Ocean Soul';
