UPDATE augments SET description = 'Grants random {{bi|Dragon Soul|Dragon Souls}}.', tier = 'Prismatic', notes = NULL WHERE name = 'Omni Soul';
UPDATE augments SET description = 'Replaces {{si|Flee}} with ''''{{si|Orbital Laser}}''''.<br><br>[[File:Orbital Laser augment spell.png|20px|link=]] {{sbc|Orbital Laser:}} {{#invoke:SpellData|geteffect|Orbital Laser}}', tier = 'Prismatic', notes = NULL WHERE name = 'Orbital Laser';
UPDATE augments SET description = '{{tip|Dash|Dashing}} or {{tip|blink|blinking}} grants {{sti|{{as|''''''bonus'''''' armor}}}} and {{sti|{{as|''''''bonus'''''' magic resistance}}}}, stacking up to 5 times. This effect lasts until the end of the current round phase.', tier = 'Gold', notes = NULL WHERE name = 'Outlaw''s Grit';
