UPDATE augments SET description = 'You constantly {{tip|heal}} while moving.', tier = 'Gold', notes = NULL WHERE name = 'Restless Restoration';
UPDATE augments SET description = 'Gain {{sti|attack range|{{rd|75|50}} ''''''bonus'''''' attack range}}.<br><br>''''Removed since [[V26.09]].''''', tier = 'Silver', notes = NULL WHERE name = 'Scoped Weapons';
UPDATE augments SET description = 'Gain {{sti|attack range|{{rd|200|100}} ''''''bonus'''''' attack range}}.<br><br>''''Removed since [[V26.09]].''''', tier = 'Gold', notes = NULL WHERE name = 'Scopier Weapons';
UPDATE augments SET description = 'Gain {{sti|attack range|''''''bonus'''''' attack range}}.', tier = 'Prismatic', notes = NULL WHERE name = 'Scopiest Weapons';
UPDATE augments SET description = 'Gain {{cai|Sunlight|Leona}}.<br><br>{{sbc|Sunlight:}} Your abilities mark enemies, causing them to take {{as|''''''bonus'''''' magic damage}} based on {{sti|{{as|their ''''''maximum'''''' health}}}} from your ally''s next basic attack or ability hit against them ({{sti|{{fd|0.75}}-second cooldown}} per target).', tier = 'Gold', notes = NULL WHERE name = 'Searing Dawn';
UPDATE augments SET description = '{{as|Automatically}} get a bomb attached to you that detonates after {{sti|cooldown|15 seconds}}, creating an explosion that deals {{as|true damage}} based on {{as|the target''s ''''''maximum'''''' health}} to enemies within 350 units and {{tip|airborne|knocks them up}} for {{fd|0.75}} seconds ({{sti|15 seconds cooldown}}).<br><br>The bomb''s duration is not refreshed when the initial delay for the combat phase elapses.', tier = 'Silver', notes = '* The {{tip|airborne}} status effect from the knock up does not interrupt {{tip|channel|channels}} nor disable {{tip|ability|abilities}}, and is not resisted by {{tip|cc-immune|immunity}} nor {{tip|spell shield}}.{{bug}}' WHERE name = 'Self Destruct';
UPDATE augments SET description = 'Upon taking fatal damage for the first time, you are restored to {{as|100% ''''''maximum'''''' health}} but suffer {{as|true damage}} over time until you die from reaching 0 health. Scoring a champion {{tip|takedown}} ends this effect''s damage immediately and sets your {{sti|{{as|''''''current'''''' health}}}} to {{as|a percentage of ''''''maximum'''''' health}}.', tier = 'Silver', notes = NULL WHERE name = 'Serve Beyond Death';
UPDATE augments SET description = 'After {{tip|dash|dashing}}, {{tip|blink|blinking}}, or exiting {{tip|stealth}}, gain {{sti|{{as|''''''bonus'''''' movement speed}}}} for a period of time.', tier = 'Silver', notes = NULL WHERE name = 'Shadow Runner';
UPDATE augments SET description = 'Basic attacks reduce the target''s damage dealt for 3 seconds, refreshing with each hit. Their {{sti|size}} is also reduced significantly for the duration.', tier = 'Gold', notes = NULL WHERE name = 'Shrink Ray';
UPDATE augments SET description = 'Hitting an enemy with a basic ability while located at least {{tip|er|icononly=true}} 700 units away from them at the time of the hit {{sti|cooldown|reduces the ''''''current'''''' cooldown}} of that ability to {{fd|0.5}} seconds. If the ability hit is from a damage over time effect, the cooldown of the ability is instead reduced to 3 seconds if it is not already below that.', tier = 'Gold', notes = NULL WHERE name = 'Skilled Sniper';
UPDATE augments SET description = '{{tip|Immobilize|Immobilizing}} or {{tip|ground|grounding}} an enemy champion grants you {{tip|adaptive force}}, stacking infinitely ({{sti|5 seconds cooldown}} per {{tip|cast instance}}). This effect lasts until the end of the current round phase.', tier = 'Silver', notes = NULL WHERE name = 'Slap Around';
UPDATE augments SET description = '{{as|Automatically}} cast {{cai|Unstable Matter|Zac}}, releasing a burst of slime in a {{tip|cr|icononly=true}} 450 radius around you and dealing {{as|{{pp|40 to 80}}|magic damage}} {{as|(+ {{pp|3 to 7|key=%}} {{as|(+ {{fd|1.5}}% per 100 ''''''bonus'''''' AD)}} {{as|(+ {{fd|1.5}}% per 100 AP)}} of target''s ''''''maximum'''''' health)}} {{as|magic damage}} to enemies hit ({{sti|7 seconds cooldown}}). Additionally, hitting a champion secretes a slime blob toward a nearby location. Both you and enemy champions can interact with the blob by moving over it; you may consume it to {{tip|heal}} yourself for {{as|{{pp|3 to 6|key=%}} of your ''''''maximum'''''' health}}, while an enemy may destroy it to deny the effect.', tier = 'Silver', notes = NULL WHERE name = 'Slime Time';
UPDATE augments SET description = 'Surrounds you in flames, causing you to apply a {{as|Burn}} every second to enemies within {{tip|cr|icononly=true}} 500 units for 5 seconds that deals {{as|magic damage}}. This {{as|Burn}} stacks infinitely and refreshes with each application.<br><br>This counts as a {{as|Burn}} source.', tier = 'Prismatic', notes = NULL WHERE name = 'Slow Cooker';
UPDATE augments SET description = 'Replaces {{si|Flee}} with ''''{{si|Mark}}'''' / ''''{{si|Dash}}''''.<br><br>{{sbc|Mark:}} Throws a snowball in the target direction that deals {{as|{{pp|15 to 100}} true damage}} to the first enemy hit and marks them for 3 seconds ({{sti|6 seconds cooldown}}). While the target is marked, you are granted the ability to cast {{si|Dash}}.<br><br>{{sbc|Dash:}} You {{tip|dash}} to the marked target while being {{tip|untargetable}}, dealing the same damage again upon arrival.', tier = 'Silver', notes = NULL WHERE name = 'Snowball Fight!';
UPDATE augments SET description = 'Granting a [[buff]], {{tip|heal}}, or {{tip|shield}} to your ally deals {{as|{{pp|30 to 150}} true damage}} to enemies within 450 units of them and {{tip|slow|slows}} targets by 30% ({{sti|2 seconds cooldown}}).', tier = 'Silver', notes = NULL WHERE name = 'Sonic Boom';
UPDATE augments SET description = 'Your {{tip|critical strike|critical strikes}} {{tip|heal}} you for a part of damage dealt. Additionally, gain {{as|25% critical strike chance}}.', tier = 'Gold', notes = NULL WHERE name = 'Soul Siphon';
UPDATE augments SET description = 'Hitting an enemy champion with an ability sends a trail centered from you to the location they were hit, detonating in a 100 width radius after {{fd|0.75}} seconds to deal {{as|magic damage}} to enemies within. This effect can only trigger once every 6 seconds from the same cast.', tier = 'Prismatic', notes = NULL WHERE name = 'Spellwake';
UPDATE augments SET description = 'Your {{tt|spinning abilities|Any ability with ''spinning'' properties}} deal increased damage and benefit from {{sti|{{as|ability haste}}}}.', tier = 'Silver', notes = NULL WHERE name = 'Spin To Win';
UPDATE augments SET description = 'Redirect a part of the damage dealt to your ally to you, and {{tip|heal}} yourself equal to a part of the healing they receive.', tier = 'Prismatic', notes = NULL WHERE name = 'Spirit Link';
UPDATE augments SET description = 'Increase the number of permanent stacks you gain from abilities by 75%.', tier = 'Silver', notes = NULL WHERE name = 'Stackosaurus Rex';
UPDATE augments SET description = 'Upon selecting this augment, gain {{ii|Stat Bonus|Stat Bonus Anvils}} for free.', tier = 'Silver', notes = NULL WHERE name = 'Stats!';
UPDATE augments SET description = 'Upon selecting this augment, gain {{ii|Stat Bonus|Stat Bonus Anvils}} for free.', tier = 'Gold', notes = NULL WHERE name = 'Stats on Stats!';
UPDATE augments SET description = 'Upon selecting this augment, gain {{ii|Stat Bonus|Stat Bonus Anvils}} for free.', tier = 'Prismatic', notes = NULL WHERE name = 'Stats on Stats on Stats!';
UPDATE augments SET description = 'The first several times you use each unique summoner spell in the current phase of the round, set its cooldown to {{sti|cooldown|3 seconds}} instead of its default. Additionally, the {{sti|cooldown}} of your {{si|Flash}} resets every round.', tier = 'Gold', notes = NULL WHERE name = 'Summoner Revolution';
UPDATE augments SET description = 'Replace both of your summoner spells with random ones available in a pool. After using a summoner spell during the combat phase, replace the spell in the respective slot with another random one.<br><br>{{sbc|Summoner Spell Pool:}} {{si|Banner of Command}}, {{si|Barrier}}, {{si|Blade Waltz}}, {{si|Castle}}, {{si|Cleanse}}, {{si|Mark}} / {{si|Dash}}, {{si|Defensive Maneuvers}}, {{si|Die Another Day}}, {{si|Exhaust}}, {{si|Feel the Burn}}, {{si|Flash}}, {{si|Flee}}, {{si|Ghost}}, {{si|Heal}}, {{si|Ignite}}, {{si|Vanish}}', tier = 'Prismatic', notes = NULL WHERE name = 'Summoner''s Roulette';
UPDATE augments SET description = 'Gain the {{ri|Conqueror}} and {{ri|Lethal Tempo}} keystone runes.<br><br>''''See [[Arena#Runes]] for Arena-specific overrides on these keystones.''''', tier = 'Prismatic', notes = '* {{ri|Lethal Tempo}} at max stack sets {{sti|attack speed|{{as|attack speed cap}}}} to {{as|10|as}}.' WHERE name = 'Symphony of War';
UPDATE augments SET description = 'Gain ''''Critical Defend Chance'''' equal to {{sti|{{as|100% of your critical strike chance}}}}, up to {{sti|50%|critical strike chance}}. Additionally, gain {{sti|{{as|25% critical strike chance}}}}.<br><br>{{sbc|Critical Defend Chance:}} Grants you a chance to reduce an instance of damage taken.', tier = 'Silver', notes = NULL WHERE name = 'Tank It Or Leave It';
UPDATE augments SET description = 'Basic attacks {{tip|on-hit}} grant {{sti|{{as|''''''bonus'''''' movement speed}}}}, stacking infinitely and lasting until the end of the current round phase. Additionally, gain {{sti|{{as|''''''bonus'''''' attack speed}}}} equal to {{sti|{{as|10% of your ''''''total'''''' movement speed}}}}.', tier = 'Prismatic', notes = NULL WHERE name = 'Tap Dancer';
UPDATE augments SET description = 'Grants {{sti|{{as|''''''bonus'''''' attack damage}}}}, {{sti|{{as|ability haste}}}}, and {{sti|{{as|lethality}}}}.', tier = 'Silver', notes = NULL WHERE name = 'The Brutalizer';
UPDATE augments SET description = 'Grants {{sti|{{as|armor penetration}}}} and {{sti|{{as|magic penetration}}}}.', tier = 'Gold', notes = NULL WHERE name = 'Thread the Needle';
UPDATE augments SET description = '{{tip|Immobilize|Immobilizing}} or {{tip|ground|grounding}} an enemy champion inflicts them with a {{as|Burn}} for 5 seconds, dealing {{as|magic damage}} based on {{sti|{{as|the target''s ''''''maximum'''''' health}}}} ({{sti|5 seconds cooldown}} per {{tip|cast instance}}). This {{as|Burn}} stacks infinitely and refreshes with each application.<br><br>This counts as a {{as|Burn}} source.', tier = 'Silver', notes = NULL WHERE name = 'Tormentor';
UPDATE augments SET description = '{{tip|Dash|Dashing}} or {{tip|blink|blinking}} causes you to inflict the nearest enemy champion within {{tip|cr|icononly=true}} 650 units with a {{as|Burn}} for 5 seconds, dealing {{as|magic damage}} based on {{sti|{{as|the target''s ''''''maximum'''''' health}}}} ({{sti|{{fd|1.5}} seconds cooldown}} per {{tip|cast instance}}). This {{as|Burn}} stacks infinitely and refreshes with each application.<br><br>This counts as a {{as|Burn}} source.', tier = 'Silver', notes = NULL WHERE name = 'Trailblazer';
UPDATE augments SET description = 'Upon damaging an enemy while located at over {{tip|cr|icononly=true}} {{tt|700 units away|center-to-edge}} at the time of the hit, cast {{cai|Trueshot Barrage|Ezreal}} in their direction. The barrage deals {{as|{{pp|175 to 525}}|magic damage}} {{as|(+ 100% ''''''bonus'''''' AD)}} {{as|(+ 70% AP)}} {{as|magic damage}} to enemies it passes through. This augment has {{sti|cooldown}} on each target.', tier = 'Prismatic', notes = NULL WHERE name = 'Trueshot Prodigy';
UPDATE augments SET description = 'Basic attacks generate a stack. At maximum stack, your next basic attack consumes all stacks to apply {{tip|on-hit}} effects again at 100% effectiveness.', tier = 'Gold', notes = NULL WHERE name = 'Twice Thrice';
UPDATE augments SET description = 'Basic attacks fire a bolt at an additional target that deals {{as|physical damage}} and applies on-hit effects at 100% effectiveness.', tier = 'Silver', notes = NULL WHERE name = 'Typhoon';
UPDATE augments SET description = 'Casting your ultimate ability resets its {{sti|cooldown}} immediately after its effect {{tt|starts|For instant-cast spells}} or has {{tt|elapsed|For duration-based spells}}. This may occur only once per phase in a round.', tier = 'Prismatic', notes = NULL WHERE name = 'Ultimate Revolution';
UPDATE augments SET description = 'Replaces {{si|Flee}} with a random champion''s ultimate ability, available from a pool. After using the granted ultimate ability during the combat phase, replace the ultimate in the respective slot with another random one after the cooldown for this effect elapses ({{pp|20 to 15 for 3|1;6;16}} seconds {{tt|cooldown|Affected by ultimate haste}}, increased to {{pp|25 to 20 for 3|1;6;16}} for {{cai|Maximum Dosage|Dr. Mundo}}).<br><br>{{sbc|Ultimate Ability Pool:}} {{cai|Feast|Cho''Gath}}, {{cai|Maximum Dosage|Dr. Mundo}}, {{cai|Cannon Barrage|Gangplank}}, {{cai|Explosive Cask|Gragas}}, {{cai|The Culling|Lucian}}, {{cai|Final Spark|Lux}}, {{cai|Soul Shackles|Morgana}}.<br><br>''''You can receive your own champion''s ultimate ability from this augment. Ultimate abilities granted by this effect count as an ultimate for all purposes.''''', tier = 'Prismatic', notes = NULL WHERE name = 'Ultimate Roulette';
UPDATE augments SET description = 'Casting your ultimate ability grants you {{tip|cc-immune|crowd control immunity}} ({{sti|8 seconds cooldown}}).', tier = 'Silver', notes = NULL WHERE name = 'Ultimate Unstoppable';
UPDATE augments SET description = 'Replaces {{si|Flee}} with ''''{{si|Vanish}}''''.<br><br>[[File:Vanish augment spell.png|20px|link=]] {{sbc|Vanish:}} {{#invoke:SpellData|geteffect|Vanish}}', tier = 'Gold', notes = NULL WHERE name = 'Vanish';
UPDATE augments SET description = 'After your ally dies once, gain increased damage and {{sti|{{as|omnivamp}}}} for the remainder of the round.', tier = 'Gold', notes = NULL WHERE name = 'Vengeance';
UPDATE augments SET description = 'Damage dealt by items and damage over time effects can now {{tip|critical strike|critically strike}} for extra damage. Additionally, gain {{sti|{{as|25% critical strike chance}}}}.<br><br>If both ''''Vulnerability'''' and [[File:Jeweled Gauntlet ar augment.png|20px|link=|An icon for the Arena augment Jeweled Gauntlet]] ''''Jeweled Gauntlet'''' are equipped, only rolls the critical strike chance of the augment that has the higher critical damage (or either if equal).', tier = 'Gold', notes = '* Certain non-damage-over-time abilities will benefit from this augment.{{bug}}
		* ''''Vulnerability'''' now stacks multiplicatively with ''''Jeweled Gauntlet'''' on those non-damage-over-time abilities.{{bug}} On damage-over-time abilities, only one of ''''Vulnerability'''' and ''''Jeweled Gauntlet'''' will take effect.' WHERE name = 'Vulnerability';
UPDATE augments SET description = 'Replaces {{si|Flee}} with ''''{{si|Warmup Routine}}''''.<br><br>[[File:Warmup Routine augment spell.png|20px|link=]] {{sbc|Warmup Routine:}} {{#invoke:SpellData|geteffect|Warmup Routine}}', tier = 'Silver', notes = NULL WHERE name = 'Warmup Routine';
UPDATE augments SET description = 'When your ally drops below {{sti|{{as|30% of their ''''''maximum'''''' health}}}}, reduce your {{sti|{{as|''''''current'''''' health}}}} by {{as|25%|health}} to grant them a {{tip|shield}} equal to {{sti|{{as|a percentage of your ''''''current'''''' health}}}} for 10 seconds.', tier = 'Gold', notes = NULL WHERE name = 'Willing Sacrifice';
UPDATE augments SET description = 'Grants 1 level upon selecting this augment and 1 additional level at the start of every other round. Additionally, the level cap for your champion is removed, allowing them to benefit from effects that scale past level 18, including stat growth.<br><br>If this augment is picked after Round 4, gain 3 levels upon selecting the augment instead of 1.', tier = 'Prismatic', notes = NULL WHERE name = 'Wisdom of Ages';
UPDATE augments SET description = 'Grants {{sti|{{as|ability power}}}}.', tier = 'Silver', notes = NULL WHERE name = 'Witchful Thinking';
UPDATE augments SET description = 'Grants {{sti|{{as|''''''bonus'''''' movement speed}}}} based on your {{sti|{{as|ability haste}}}}.', tier = 'Gold', notes = NULL WHERE name = 'With Haste';

